mapper.select:
SELECT 
FROM tb_mdm_configuration_option_code t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.configuration_code = #{configurationCode}


    AND t.option_family_code = #{optionFamilyCode}


    AND t.option_code = #{optionCode}


    AND t.feature_type = #{optionType}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

SELECT FROM tb_mdm_configuration_option_code t WHERE t.row_valid = 1
AND t.configuration_code = #{configurationCode}
ORDER BY t.option_family_code ASC

SELECT 
FROM tb_mdm_configuration_option_code t
WHERE t.row_valid = 1
AND t.configuration_code = #{configurationCode}
AND t.option_family_code = #{optionFamilyCode}
LIMIT 1

SELECT t.configuration_code FROM tb_mdm_configuration_option_code t WHERE t.row_valid = 1 AND (
(t.option_family_code = #{optionFamilyCode} AND FIND_IN_SET(#{optionCode}, t.option_code) > 0)
) GROUP BY t.configuration_code HAVING COUNT(DISTINCT t.option_family_code) = #{optionFamilyCount}
